'use client'

import Image from 'next/image'
import Link from 'next/link'
import { useRef } from 'react'
import { motion, useInView } from 'framer-motion'
import {
  ArrowRight, Wrench, Flame, HardHat, Anchor,
  Zap, Construction, Layers, Building2, Package,
} from 'lucide-react'

// ─── helpers ─────────────────────────────────────────────────────────────────

function renderIcon(type: string, size = 14) {
  const p = { size, color: 'currentColor' }
  switch (type) {
    case 'wrench':       return <Wrench {...p} />
    case 'flame':        return <Flame {...p} />
    case 'hardhat':      return <HardHat {...p} />
    case 'anchor':       return <Anchor {...p} />
    case 'zap':          return <Zap {...p} />
    case 'construction': return <Construction {...p} />
    case 'layers':       return <Layers {...p} />
    case 'building2':    return <Building2 {...p} />
    case 'package':      return <Package {...p} />
    default:             return <Wrench {...p} />
  }
}

function Reveal({ children, delay = 0, dir = 'up', className = '' }: {
  children: React.ReactNode; delay?: number; dir?: 'up' | 'left' | 'right' | 'scale'; className?: string
}) {
  const ref = useRef<HTMLDivElement>(null)
  const inView = useInView(ref, { once: true, margin: '-80px' })
  const init = { up: { y: 40, x: 0 }, left: { y: 0, x: -40 }, right: { y: 0, x: 40 }, scale: { y: 0, x: 0 } }
  return (
    <motion.div
      ref={ref}
      initial={{ opacity: 0, ...init[dir], scale: dir === 'scale' ? 0.94 : 1 }}
      animate={inView ? { opacity: 1, x: 0, y: 0, scale: 1 } : {}}
      transition={{ duration: 0.7, delay, ease: [0.25, 0.1, 0.25, 1] }}
      className={className}
    >
      {children}
    </motion.div>
  )
}

// ─── product data ─────────────────────────────────────────────────────────────

const PRODUCTS = [
  { slug: 'fasteners',               name: 'Fasteners',             iconType: 'wrench',       image: '/images/products/fastner.png' },
  { slug: 'welding-consumables',     name: 'Welding Consumables',   iconType: 'flame',        image: '/images/products/welding-consumable.png' },
  { slug: 'ppe-safety',              name: 'Safety PPE',            iconType: 'hardhat',      image: '/images/products/saftlyppes.png' },
  { slug: 'lifting-solutions',       name: 'Lifting Solutions',     iconType: 'anchor',       image: '/images/products/lifting-solutions.png' },
  { slug: 'hand-tools',              name: 'Hand Tools',            iconType: 'wrench',       image: '/images/products/handtools.png' },
  { slug: 'power-tools',             name: 'Power Tools',           iconType: 'zap',          image: '/images/products/powertools.png' },
  { slug: 'machine-pneumatic-tools', name: 'Machine & Pneumatic',   iconType: 'construction', image: '/images/products/machinetools.png' },
  { slug: 'pipes-fittings',          name: 'Pipes & Fittings',      iconType: 'layers',       image: '/images/products/pipes&fillers.png' },
  { slug: 'fabrications',            name: 'Fabrications',          iconType: 'building2',    image: '/images/products/fabrication.png' },
]

// ─── floater config ───────────────────────────────────────────────────────────
//
//  PLACEMENT LOGIC:
//  • Grid uses padding: 0 8vw — so gutters are 8vw wide on each side.
//  • Floaters live at sidePos ≈ 0–2vw from the edge, meaning they sit
//    mostly in the gutter and only barely kiss the grid border.
//    → zero collision with card text at any viewport.
//
//  • topPct uses percentages so positions scale with section height on
//    any screen size — no more broken pixel positions.
//
//  • 3 pairs (top / mid / bottom) evenly distributed:
//      Pair A:  3%        ← header zone
//      Pair B: 38–44%     ← between row 1 and row 2
//      Pair C: 68–72%     ← between row 2 and row 3
//
//  • size: 130–148px — smaller = refined accent, not obstacle
//  • rot:  initial tilt in degrees (CSS variable fed into keyframe)
//  • dur / delay: each item has a different speed so they never sync

const FLOATERS: {
  src: string
  side: 'left' | 'right'
  sidePos: string
  topPct: string
  size: number
  rot: number
  dur: number
  delay: number
}[] = [
  // ── Pair A — top, flanking the header ──
  { src: '/images/fasteners/helmate.png', side: 'left',  sidePos: '0.8vw', topPct: '2%',  size: 140, rot: -7,  dur: 5.8, delay: 0.3 },
  { src: '/images/fasteners/stipper.png', side: 'right', sidePos: '0.8vw', topPct: '2%',  size: 132, rot:  6,  dur: 6.4, delay: 1.1 },
  // ── Pair B — mid, flanking rows 1–2 boundary ──
  { src: '/images/fasteners/bolt.png',    side: 'left',  sidePos: '0.8vw', topPct: '38%', size: 148, rot: -4,  dur: 5.3, delay: 0.7 },
  { src: '/images/fasteners/wrench.png',  side: 'right', sidePos: '0.8vw', topPct: '44%', size: 145, rot:  9,  dur: 7.1, delay: 2.2 },
  // ── Pair C — lower, flanking rows 2–3 boundary ──
  { src: '/images/fasteners/nut.png',     side: 'left',  sidePos: '0.8vw', topPct: '70%', size: 135, rot: -3,  dur: 6.2, delay: 1.6 },
  { src: '/images/fasteners/wrench2.png', side: 'right', sidePos: '0.8vw', topPct: '68%', size: 138, rot:  6,  dur: 7.5, delay: 3.0 },
]

// ─── component ────────────────────────────────────────────────────────────────

export default function ProductsSection() {
  return (
    <section
      style={{
        background: '#f7f7f7',
        padding: '100px 0 120px',
        position: 'relative',
        fontFamily: "'Barlow', sans-serif",
        overflow: 'visible',    // never clip the gutter floaters
      }}
    >
      {/* ── global styles: single float keyframe + hover helpers ── */}
      <style>{`
        /* One unified animation — varied timing per item keeps movement organic */
        @keyframes floatItem {
          0%,100% { transform: translateY(0px)   rotate(var(--f-rot)); }
          50%      { transform: translateY(-13px) rotate(calc(var(--f-rot) * -0.5)); }
        }

        /* card image scale on link hover */
        .pcard-link:hover .pcard-img  { transform: scale(1.06) !important; }

        /* "View" label slides up on link hover */
        .pcard-link:hover .pcard-view { opacity: 1 !important; transform: translateY(0) !important; }
      `}</style>

      {/* ── ambient blobs — very soft, just adds depth ── */}
      <div style={{ position: 'absolute', width: 440, height: 440, top: -80, left: -100, borderRadius: '50%', background: 'radial-gradient(circle, rgba(226,0,16,0.06) 0%, transparent 70%)', pointerEvents: 'none', zIndex: 0 }} />
      <div style={{ position: 'absolute', width: 400, height: 400, bottom: 0, right: -90,  borderRadius: '50%', background: 'radial-gradient(circle, rgba(226,0,16,0.06) 0%, transparent 70%)', pointerEvents: 'none', zIndex: 0 }} />

      {/* ══════ FLOATING PRODUCT IMAGES ══════
          Each floater:
          • Sits in the gutter (≈ 8vw padding on each side)
          • Uses % top so it's responsive at any viewport height
          • One keyframe (floatItem) + CSS var for unique starting tilt
          • Single refined shadow — not stacked doubles
      */}
      {FLOATERS.map((f, i) => (
        <div
          key={i}
          style={{
            position: 'absolute',
            width:  f.size,
            height: f.size,
            top:    f.topPct,
            [f.side]: f.sidePos,
            zIndex: 4,
            pointerEvents: 'none',
            // feed rotation into the CSS keyframe as a variable
            ['--f-rot' as string]: `${f.rot}deg`,
            animation: `floatItem ${f.dur}s cubic-bezier(0.37,0,0.63,1) ${f.delay}s infinite`,
          }}
        >
          {/* soft halo disc — stays behind the image */}
          <div
            style={{
              position: 'absolute',
              inset: -16,
              borderRadius: '50%',
              background: 'radial-gradient(circle, rgba(226,0,16,0.11) 0%, transparent 65%)',
              zIndex: -1,
            }}
          />
          <img
            src={f.src}
            alt=""
            draggable={false}
            style={{
              width: '100%',
              height: '100%',
              objectFit: 'contain',
              // clean single-layer shadow — not stacked
              filter: 'drop-shadow(0 10px 24px rgba(226,0,16,0.32)) drop-shadow(0 3px 8px rgba(0,0,0,0.28))',
              userSelect: 'none',
            }}
          />
        </div>
      ))}

      {/* ══════ HEADER ══════ */}
      <div style={{ maxWidth: 1280, margin: '0 auto', padding: '0 6vw 52px', position: 'relative', zIndex: 3 }}>
        <div style={{ display: 'flex', alignItems: 'flex-end', justifyContent: 'space-between', gap: 20, flexWrap: 'wrap' }}>
          <div>
            <Reveal>
              <div style={{ display: 'inline-flex', alignItems: 'center', gap: 10, fontSize: 10, fontWeight: 700, color: '#E20010', letterSpacing: '5px', textTransform: 'uppercase' as const, marginBottom: 16 }}>
                <span style={{ width: 24, height: 2, background: '#E20010', display: 'inline-block', flexShrink: 0 }} />
                Our Products
              </div>
            </Reveal>
            <Reveal delay={0.05}>
              <h2 style={{ fontFamily: "'Barlow Condensed', sans-serif", fontSize: 'clamp(38px,4.5vw,60px)', fontWeight: 900, lineHeight: 0.92, letterSpacing: '-2px', color: '#111', textTransform: 'uppercase' as const, margin: 0 }}>
                Products Built for<br />
                <span style={{ color: '#E20010' }}>Every Industry</span>
              </h2>
            </Reveal>
          </div>
          <Reveal delay={0.1} dir="right">
            <p style={{ fontSize: 13, color: '#6b6b6b', lineHeight: 1.75, maxWidth: 300, margin: 0 }}>
              Oil &amp; gas, construction, healthcare, automation, coal &amp; cement, metal &amp; mines — solutions for every sector.
            </p>
          </Reveal>
        </div>
      </div>

      {/* ══════ PRODUCT GRID — 3×3 ══════ */}
      {/*
        padding: 0 8vw matches the floater gutter width exactly.
        gap: 2 + background: #d8d8d8 on parent = hairline dividers
        (cleaner than 14px visible gaps)
      */}
      <div style={{ maxWidth: 1280, margin: '0 auto', padding: '0 8vw', position: 'relative', zIndex: 3 }}>
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(3, 1fr)',
            gap: 2,
            borderRadius: 12,
            overflow: 'hidden',
            background: '#d8d8d8',
          }}
        >
          {PRODUCTS.slice(0, 9).map((p, i) => (
            <Reveal key={p.slug} delay={(i % 3) * 0.07}>
              <Link href={`/products/${p.slug}`} className="pcard-link" style={{ textDecoration: 'none', display: 'block' }}>
                <motion.div
                  whileHover={{ y: -5, boxShadow: '0 20px 48px rgba(226,0,16,0.2)' }}
                  transition={{ duration: 0.28, ease: 'easeOut' }}
                  style={{ position: 'relative', overflow: 'hidden', cursor: 'pointer', background: '#1a1a1a', height: 280 }}
                >
                  {/* product photo */}
                  <Image
                    src={p.image}
                    alt={p.name}
                    fill
                    className="pcard-img"
                    style={{ objectFit: 'cover', transition: 'transform .55s cubic-bezier(.25,.1,.25,1)' }}
                  />

                  {/* gradient vignette */}
                  <div style={{ position: 'absolute', inset: 0, background: 'linear-gradient(to top, rgba(0,0,0,0.92) 0%, rgba(0,0,0,0.28) 45%, rgba(0,0,0,0) 100%)' }} />

                  {/* index */}
                  <div style={{ position: 'absolute', top: 12, left: 14, fontSize: 9, fontWeight: 800, color: 'rgba(255,255,255,0.2)', letterSpacing: '3px', zIndex: 2 }}>
                    {String(i + 1).padStart(2, '0')}
                  </div>

                  {/* category icon badge */}
                  <div style={{ position: 'absolute', top: 10, right: 10, width: 30, height: 30, borderRadius: 7, background: 'rgba(226,0,16,0.9)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 2, color: '#fff' }}>
                    {renderIcon(p.iconType, 13)}
                  </div>

                  {/* bottom label block */}
                  <div style={{ position: 'absolute', bottom: 0, left: 0, right: 0, padding: '16px 18px', zIndex: 2 }}>
                    <div style={{ fontSize: 8, fontWeight: 700, color: '#E20010', letterSpacing: '2.5px', textTransform: 'uppercase' as const, marginBottom: 5 }}>
                      Category {String(i + 1).padStart(2, '0')}
                    </div>
                    <h3 style={{ fontFamily: "'Barlow Condensed', sans-serif", fontSize: 19, fontWeight: 900, color: '#fff', margin: 0, lineHeight: 1.05, textTransform: 'uppercase' as const }}>
                      {p.name}
                    </h3>
                    {/* view arrow — CSS hover via .pcard-link:hover .pcard-view */}
                    <div
                      className="pcard-view"
                      style={{ marginTop: 9, display: 'flex', alignItems: 'center', gap: 6, opacity: 0, transform: 'translateY(6px)', transition: 'opacity .28s, transform .28s' }}
                    >
                      <div style={{ width: 18, height: 1, background: 'rgba(226,0,16,0.8)' }} />
                      <span style={{ fontSize: 8, fontWeight: 700, color: 'rgba(255,255,255,0.5)', letterSpacing: '2px', textTransform: 'uppercase' as const }}>View</span>
                    </div>
                  </div>

                  {/* inset red border reveals on hover */}
                  <motion.div
                    initial={{ opacity: 0 }}
                    whileHover={{ opacity: 1 }}
                    style={{ position: 'absolute', inset: 0, boxShadow: 'inset 0 0 0 1.5px rgba(226,0,16,0.55)', pointerEvents: 'none', zIndex: 3 }}
                  />
                </motion.div>
              </Link>
            </Reveal>
          ))}
        </div>
      </div>

      {/* ══════ CTA ══════ */}
      <div style={{ textAlign: 'center', marginTop: 60, padding: '0 8vw', position: 'relative', zIndex: 3 }}>
        <Reveal delay={0.2}>
          <motion.button
            whileHover={{ backgroundColor: '#E20010', color: '#fff' }}
            onClick={() => (window.location.href = '/products')}
            style={{
              display: 'inline-flex', alignItems: 'center', gap: 10,
              fontSize: 11, fontWeight: 700, letterSpacing: '3px',
              textTransform: 'uppercase' as const, padding: '15px 48px',
              border: '2px solid #E20010', color: '#E20010',
              background: 'transparent', borderRadius: 6, cursor: 'pointer',
              fontFamily: "'Barlow', sans-serif", transition: 'all .3s',
            }}
          >
            View All Products <ArrowRight size={14} />
          </motion.button>
        </Reveal>
      </div>
    </section>
  )
}